<?php namespace App\Repositories\Alumni;use App\Repositories\BaseRepository;use App\Models\Alumni\Alumni;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class AlumniRepository extends BaseRepository{    public function __construct(Alumni $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByGraduationYear(int $year): Collection    {        return $this->findByField('graduation_year', $year);    }    public function findByOccupation(string $occupation): Collection    {        return $this->findByField('occupation', $occupation);    }    public function findByIndustry(string $industry): Collection    {        return $this->findByField('industry', $industry);    }    public function findByLocation(string $city, string $country = null): Collection    {        $query = $this->query()->where('city', 'like', "%{$city}%");        if ($country) {            $query->where('country', $country);        }        return $query->get();    }    public function searchAlumni(string $keyword): Collection    {        return $this->query()->where('first_name', 'like', "%{$keyword}%")->orWhere('last_name', 'like', "%{$keyword}%")->orWhere('email', 'like', "%{$keyword}%")->orWhere('phone', 'like', "%{$keyword}%")->orWhere('company', 'like', "%{$keyword}%")->get();    }    public function getConnectedAlumni(): Collection    {        return $this->query()->where('is_connected', true)->get();    }    public function getVerifiedAlumni(): Collection    {        return $this->query()->where('is_verified', true)->get();    }    public function getByPassoutBatch(int $startYear, int $endYear): Collection    {        return $this->query()->whereBetween('graduation_year', [$startYear, $endYear])->get();    }    public function getAlumniByClass(int $classId): Collection    {        return $this->query()->where('last_class_id', $classId)->get();    }    public function countByGraduationYear(): Collection    {        return $this->query()->selectRaw('graduation_year, COUNT(*) as total')->groupBy('graduation_year')->orderBy('graduation_year', 'desc')->get();    }    public function updateContactInfo(int $id, array $data): bool    {        return $this->update($id, $data);    }}